#include <iostream>
#include <string>
using namespace std;

class Player {
private:
    string name;
    int hp;
public:
    Player(string n, int h) : name(n), hp(h) {}

    void info() {
        cout << name << " | HP: " << hp << endl;
    }

    void takeDamage(int dmg) {
        hp -= dmg;
        if (hp < 0) hp = 0;
    }
};

int main() {
    Player hero("Warrior", 100);
    hero.info();
    hero.takeDamage(30);
    hero.info();
    return 0;
}

